SELECT EXISTS(
    SELECT 1 FROM wishlist
     WHERE member_id = #{memberId} AND recipe_id = #{recipeId}
)

SELECT recipeId, name FROM ( SELECT ri.recipe_id AS recipeId, ri.name AS name, ROW_NUMBER() OVER (PARTITION BY ri.recipe_id ORDER BY ri.ingredient_id) AS rn FROM recipe_ingredient ri WHERE ri.recipe_id IN
#{id}
) t WHERE t.rn <= 3 ORDER BY recipeId, rn

SELECT member_id FROM ai_recipe
 WHERE ai_recipe_id = #{aiRecipeId}
 LIMIT 1
